import{_ as t,o as a,c as s,a3 as i}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"Campaign Management","description":"","frontmatter":{"title":"Campaign Management"},"headers":[],"relativePath":"en/faq/campaign-management.md","filePath":"en/faq/campaign-management.md"}'),o={name:"en/faq/campaign-management.md"};function r(n,e,l,m,c,d){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="campaign-management" tabindex="-1">Campaign Management <a class="header-anchor" href="#campaign-management" aria-label="Permalink to &quot;Campaign Management&quot;">​</a></h1><details class="details custom-block"><summary>What is the expected response time?</summary><p>You must respond within <strong>48 working hours</strong>. Responsiveness is the key to winning campaigns against other retailers. Past this deadline, getinside reserves the right to refuse the campaign on your behalf and apply a penalty corresponding to the planned platform fees.</p></details><details class="details custom-block"><summary>Can I cancel an already accepted campaign?</summary><p>Cancellation is highly discouraged. Except in cases of force majeure, penalties apply:</p><ul><li>Flat penalty of <strong>250€</strong></li><li>+ Reimbursement of lost platform fees</li><li>+ Reimbursement of production costs (if printed) and studio costs incurred</li></ul></details><details class="details custom-block"><summary>Can I refuse to insert a received flyer?</summary><p>Yes. Check the merchandise upon receipt. If the materials are damaged or do not comply with the validated proof (e.g., competing brand not reported), immediately contact support (<code>studio@getinside.fr</code>) and suspend the insertion.</p></details><details class="details custom-block"><summary>The campaign is starting late — what to do?</summary><p>If you haven&#39;t distributed anything over a planned week:</p><ol><li>Enter <strong>&quot;0&quot;</strong> in the weekly reporting.</li><li>Notify the advertiser via messaging.</li></ol><p>The platform will automatically extend the campaign at the end of the period to reach the target volume.</p></details><details class="details custom-block"><summary>How to add a new type of offer?</summary><p>Go to the relevant audience profile and add a campaign type. For a custom offer (outside the standard catalog), select <strong>&quot;Other campaign type&quot;</strong> — the getinside team will validate the feasibility with you.</p></details><details class="details custom-block"><summary>Where to see my campaign history?</summary><ul><li><strong>Received campaigns (Retailer):</strong> Monetization → Campaign manager (filter by status: Accepted, Refused...)</li><li><strong>Your own campaigns (Advertiser):</strong> Campaigns → All campaigns</li></ul></details><details class="details custom-block"><summary>How to track the performance of my campaign?</summary><p>You have dual tracking on your getinside dashboard:</p><ol><li><strong>Performance (ROI):</strong> Scans of your QR codes in real-time.</li><li><strong>Distribution:</strong> Volumes of inserted flyers updated every beginning of the week by the distributor.</li></ol></details><details class="details custom-block"><summary>A distributor refuses my visual — what to do?</summary><p>The distributor has a <strong>veto right over the brand</strong> (direct competitor, ethically incompatible category) — but not over the art direction.</p><p>If your visual meets the technical specifications (2mm bleed, 3mm quiet zone, 300 DPI resolution, legal mentions present), it is compliant. The distributor cannot reject it for subjective reasons of taste or style.</p><p><strong>Procedure:</strong></p><ol><li>Check that your file respects the <a href="/handbook/en/advertisers/sponsored-mail/design-guide/print-specs.html">print specifications</a>.</li><li>If everything is compliant, send your proof to <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a> for official validation.</li><li>The getinside validation takes precedence over the subjective appreciation of the distributor.</li></ol></details><details class="details custom-block"><summary>An advertiser asks for the addresses of my customers — can I give them?</summary><p><strong>No, under no circumstances.</strong> This request is contrary to GDPR and our Terms of Service.</p><p>Your customer data is a <strong>First Party</strong> asset that belongs exclusively to you. getinside operates as a <strong>Trusted Third Party</strong>: the advertiser accesses your audience without ever receiving the file. No database transfer is allowed without specific opt-in from each customer.</p><p>In case of an insistent request, contact <a href="mailto:support@getinside.fr" target="_blank" rel="noreferrer">support@getinside.fr</a> — our team handles the legal response.</p></details>',10)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
